sendProtocolMessage.text:
function sendProtocolMessage(agent: string, type: MessageType, content: string, to: string | null = null): void {
  if (!MESSAGE_TYPES.includes(type)) throw new Error('Invalid message type');
  addAgentMessage(agent, type, { to, content });
}

isProtocolMessage.text:
function isProtocolMessage(m: any): m is ProtocolMessage {
  return m && typeof m === 'object' && 'timestamp' in m && 'agent' in m && 'type' in m && 'message' in m;
}

readProtocolMessages.text:
function readProtocolMessages({ type, agent, to }: { type?: MessageType; agent?: string; to?: string } = {}): ProtocolMessage[] {
  return (getAgentMessages()
    .filter(isProtocolMessage)
    .filter((m) =>
      (!type || m.type === type) &&
      (!agent || m.agent === agent) &&
      (!to || (m.message && typeof m.message === 'object' && 'to' in m.message && (m.message as { to?: string | null }).to === to))
    ) as unknown) as ProtocolMessage[];
}

getRecentMessages.text:
export function getRecentMessages(n: number): ProtocolMessage[] {
  return (getAgentMessages().filter(isProtocolMessage).slice(-n) as unknown) as ProtocolMessage[];
}

