isValidPluginModule.text:
function isValidPluginModule(mod: unknown): mod is PluginModule {
  if (!mod || typeof mod !== 'object') return false;
  const m = mod as PluginModule;
  // Must have a name and at least one of run or describe
  if (typeof m.name !== 'string') return false;
  if (typeof m.run !== 'function' && typeof m.describe !== 'function') return false;
  // If run exists, check for Zod validation pattern (optional, best effort)
  if (typeof m.run === 'function' && m.describe && typeof m.describe === 'function') {
    const desc = m.describe();
    if (desc && typeof desc === 'object' && 'schema' in desc && desc.schema && typeof desc.schema === 'object') {
      const schema = (desc as { schema?: { input?: unknown; output?: unknown } }).schema;
      if (schema && 'input' in schema && 'output' in schema) {
        // Optionally check if input/output are Zod schemas
        if (z.ZodType && schema.input instanceof z.ZodType && schema.output instanceof z.ZodType) {
          return true;
        }
      }
    }
  }
  // Allow plugins that only implement onEvent/initialize for now
  return true;
}

