export async function getPlugins(): Promise<PluginModule[]> {
  const { ensureCacheDirExists } = await import('./utils/context/cacheDir.js');
  await ensureCacheDirExists();
  if (!fs.existsSync(PLUGIN_DIR)) return [];
  const files = fs.readdirSync(PLUGIN_DIR).filter(f => f.endsWith('.js') || f.endsWith('.ts'));
  const plugins: PluginModule[] = [];
  for (const file of files) {
    try {
      const mod = await import(path.join(PLUGIN_DIR, file));
      if (isValidPluginModule(mod) && (mod.describe || mod.run)) {
        // Avoid duplicate 'name' property if already present in mod
        if (typeof mod === 'object' && mod !== null) {
          const m = mod as { name?: unknown };
          if (typeof m.name === 'string') {
            const pluginObj: Partial<PluginModule> = { ...(mod as object) };
            if (typeof pluginObj.name === 'string') {
              plugins.push(pluginObj as PluginModule);
            }
          } else {
            const pluginWithName: Partial<PluginModule> = {
              name: file.replace(/\.(js|ts)$/, ''),
              ...(mod as object)
            };
            if (typeof pluginWithName.name === 'string') {
              plugins.push(pluginWithName as PluginModule);
            }
            // else skip if name is not string
          }
        }
        // else skip if not an object
      } else {
        if (process.env['AIHELPERS_DEBUG']) {
          console.warn(`[pluginRegistry] Skipping invalid plugin ${file}: does not conform to PluginModule interface or lacks Zod validation.`);
        }
      }
    } catch (e) {
      // Ignore broken plugins, but log in debug mode
      if (process.env['AIHELPERS_DEBUG']) {
        console.error(`[pluginRegistry] Failed to load plugin ${file}:`, e);
      }
    }
  }
  return plugins;
}

isAgentEvent.text:
function isAgentEvent(event: unknown): event is AgentEvent {
  return validateAgentEvent(event).success;
}

createPluginManager.text:
export function createPluginManager(appContext: PluginAppContext): PluginManager {
  const manager = new DefaultPluginManager(appContext);
  // Patch appContext to allow plugins to register tracked subscriptions
  (appContext as any).pluginManager = manager;
  appContext.subscribeToEvent = (type: string, handler: (event: AgentEvent) => void | Promise<void>, pluginName?: string) => {
    manager.subscribe(type, handler, pluginName);
  };
  return manager;
}

getPluginHealthStatus.text:
export async function getPluginHealthStatus(manager?: PluginManager): Promise<Record<string, unknown>> {
  // If a manager is provided, use its aggregateHealth; otherwise, create a temp manager and load plugins
  if (manager && typeof (manager as any).aggregateHealth === 'function') {
    return await (manager as any).aggregateHealth();
  }
  // Fallback: load plugins and aggregate health
  const plugins = await getPlugins();
  const health: Record<string, unknown> = {};
  for (const plugin of plugins) {
    if (typeof (plugin as any).health === 'function') {
      try {
        health[plugin.name] = await (plugin as any).health();
      } catch (e) {
        health[plugin.name] = { status: 'error', error: String(e), timestamp: new Date().toISOString() };
      }
    } else {
      health[plugin.name] = { status: 'unknown', error: 'No health() method', timestamp: new Date().toISOString() };
    }
  }
  return health;
}

getPluginErrorStatus.text:
export async function getPluginErrorStatus(manager?: PluginManager): Promise<Record<string, unknown>> {
  // If a manager is provided, use its plugins array; otherwise, load plugins
  const plugins = manager && typeof (manager as any).plugins === 'object'
    ? (manager as any).plugins as Plugin[]
    : await getPlugins();
  const errors: Record<string, unknown> = {};
  for (const plugin of plugins) {
    if (typeof (plugin as any).getLastError === 'function') {
      try {
        errors[plugin.name] = await (plugin as any).getLastError();
      } catch (e) {
        errors[plugin.name] = { error: String(e), timestamp: new Date().toISOString() };
      }
    } else {
      errors[plugin.name] = undefined;
    }
  }
  return errors;
}

DefaultPluginManager.text:
class DefaultPluginManager implements PluginManager {
  private plugins: Plugin[] = [];
  private eventHandlers: Map<string, ((event: AgentEvent) => void | Promise<void>)[]> = new Map();
  private appContext: PluginAppContext;
  // Track event subscriptions per plugin
  private pluginSubscriptions: Map<string, { type: string; handler: (event: AgentEvent) => void | Promise<void> }[]> = new Map();
  private tracer = getTracer('PluginManager');

  /**
   * Integrate registry-driven event bus into PluginManager.
   * All plugins receive appContext.publishEvent and appContext.subscribeToEvent,
   * which delegate to the selected distributed event bus backend (Kafka/NATS/Dapr/JSONL).
   */
  constructor(appContext: PluginAppContext) {
    this.appContext = appContext;
    this.appContext.publishEvent = publishEvent;
    this.appContext.subscribeToEvent = (type: string, handler: (event: AgentEvent) => void | Promise<void>) => {
      // Use distributed event bus for topic subscription
      void subscribeToTopic(String(type), async (event) => { await handler(event); });
    };
  }

  /**
   * Registers a plugin and its event handlers. Logs lifecycle events and emits OTel spans/metrics.
   */
  register(plugin: Plugin, appContext: PluginAppContext = this.appContext) {
    this.tracer.startActiveSpan('PluginManager.register', span => {
      try {
        span.setAttribute('plugin.name', typeof plugin.name === 'string' ? plugin.name : 'unknown');
        plugin.initialize(appContext);
        this.plugins.push(plugin);
        if (plugin.onEvent) {
          const pluginName = typeof plugin.name === 'string' ? plugin.name : 'unknown';
          this.subscribe('*', plugin.onEvent.bind(plugin), pluginName);
        }
        pluginRegisteredCounter.add(1, { plugin: typeof plugin.name === 'string' ? plugin.name : 'unknown' });
        span.setStatus({ code: 1 }); // OK
        this.appContext.publishEvent({
          type: 'Log',
          agentId: 'PluginManager',
          timestamp: new Date().toISOString(),
          payload: { level: 'info', message: `Registered plugin: ${typeof plugin.name === 'string' ? plugin.name : 'unknown'}` }
        });
        console.info(`[PluginManager] Registered plugin: ${typeof plugin.name === 'string' ? plugin.name : 'unknown'}`);
      } catch (e) {
        pluginErrorCounter.add(1, { plugin: typeof plugin.name === 'string' ? plugin.name : 'unknown', event: 'register' });
        span.setStatus({ code: 2, message: String(e) });
        this.appContext.publishEvent({
          type: 'Log',
          agentId: 'PluginManager',
          timestamp: new Date().toISOString(),
          payload: {
            level: 'error',
            message: `Failed to register plugin: ${typeof plugin.name === 'string' ? plugin.name : 'unknown'}`,
            error: {
              type: e instanceof Error ? e.name : typeof e,
              message: e instanceof Error ? e.message : String(e),
              stack: e instanceof Error ? e.stack : undefined,
              context: { event: 'register' }
            }
          }
        });
        console.error(`[PluginManager] Failed to register plugin: ${typeof plugin.name === 'string' ? plugin.name : 'unknown'}`, e);
      } finally {
        span.end();
      }
    });
  }

  /**
   * Unregisters (unloads) a plugin by name. Cleans up event handlers. Logs lifecycle events.
   */
  unregister(name: string) {
    this.tracer.startActiveSpan('PluginManager.unregister', span => {
      try {
        span.setAttribute('plugin.name', name);
        this.unloadPlugin(name);
        pluginUnregisteredCounter.add(1, { plugin: name });
        span.setStatus({ code: 1 });
      } catch (e) {
        pluginErrorCounter.add(1, { plugin: name, event: 'unregister' });
        span.setStatus({ code: 2, message: String(e) });
        this.appContext.publishEvent({
          type: 'Log',
          agentId: 'PluginManager',
          timestamp: new Date().toISOString(),
          payload: {
            level: 'error',
            message: `Failed to unregister plugin: ${name}`,
            error: {
              type: e instanceof Error ? e.name : typeof e,
              message: e instanceof Error ? e.message : String(e),
              stack: e instanceof Error ? e.stack : undefined,
              context: { event: 'unregister' }
            }
          }
        });
      } finally {
        span.end();
      }
    });
  }

  /**
   * Lists all currently loaded plugins.
   */
  list() {
    return [...this.plugins];
  }

  /**
   * Emits an event to all registered handlers. Validates event type at runtime.
   */
  emitEvent(event: AgentEvent): Promise<void> {
    return new Promise(resolve => {
      this.tracer.startActiveSpan('PluginManager.emitEvent', span => {
        try {
          span.setAttribute('event.type', String(event.type));
          if (!isAgentEvent(event)) throw new Error('Invalid AgentEvent');
          for (const handler of [
            ...(this.eventHandlers.get(typeof event.type === 'string' ? event.type : '') || []),
            ...(this.eventHandlers.get('*') || [])
          ]) {
            try {
              handler(event);
            } catch (e) {
              span.addEvent('handler.error', { error: String(e) });
              console.error(`[PluginManager] Error in event handler for event type: ${event.type}`, e);
            }
          }
          span.setStatus({ code: 1 });
        } catch (e) {
          span.setStatus({ code: 2, message: String(e) });
        } finally {
          span.end();
          resolve();
        }
      });
    });
  }

  /**
   * Subscribes a handler to an event type, tracking by plugin. Logs subscription.
   */
  subscribe(type: string, handler: (event: AgentEvent) => void | Promise<void>, pluginName?: string) {
    this.tracer.startActiveSpan('PluginManager.subscribe', span => {
      try {
        span.setAttribute('event.type', type);
        if (pluginName) span.setAttribute('plugin.name', pluginName);
        const typeKey = typeof type === 'string' ? type : '';
        if (!this.eventHandlers.has(typeKey)) this.eventHandlers.set(typeKey, []);
        this.eventHandlers.get(typeKey)!.push(handler);
        if (pluginName) {
          if (!this.pluginSubscriptions.has(pluginName)) this.pluginSubscriptions.set(pluginName, []);
          this.pluginSubscriptions.get(pluginName)!.push({ type, handler });
        }
        span.setStatus({ code: 1 });
        console.info(`[PluginManager] Plugin '${pluginName}' subscribed to event type: ${type}`);
      } catch (e) {
        span.setStatus({ code: 2, message: String(e) });
      } finally {
        span.end();
      }
    });
  }

  /**
   * Dynamically loads a plugin from disk and registers it. Logs lifecycle events.
   */
  async loadPluginFromDisk(entry: string): Promise<Plugin | null> {
    return this.tracer.startActiveSpan('PluginManager.loadPluginFromDisk', async span => {
      try {
        const mod = await import(entry);
        if (isValidPluginModule(mod)) {
          pluginLoadCounter.add(1, { entry });
          span.setStatus({ code: 1 });
          return mod as unknown as Plugin;
        } else {
          pluginErrorCounter.add(1, { entry, event: 'load' });
          span.setStatus({ code: 2, message: 'Invalid plugin module' });
          return null;
        }
      } catch (e) {
        pluginErrorCounter.add(1, { entry, event: 'load' });
        span.setStatus({ code: 2, message: String(e) });
        this.appContext.publishEvent({
          type: 'Log',
          agentId: 'PluginManager',
          timestamp: new Date().toISOString(),
          payload: {
            level: 'error',
            message: `Failed to load plugin from disk: ${entry}`,
            error: {
              type: e instanceof Error ? e.name : typeof e,
              message: e instanceof Error ? e.message : String(e),
              stack: e instanceof Error ? e.stack : undefined,
              context: { event: 'load' }
            }
          }
        });
        return null;
      } finally {
        span.end();
      }
    });
  }

  /**
   * Unloads (destroys) a plugin by name and removes all event subscriptions. Logs lifecycle events.
   */
  unloadPlugin(name: string) {
    this.tracer.startActiveSpan('PluginManager.unloadPlugin', span => {
      try {
        span.setAttribute('plugin.name', name);
        const idx = this.plugins.findIndex(p => p.name === name);
        if (idx !== -1) {
          const plugin = this.plugins[idx];
          if (plugin) {
            try {
              plugin.destroy?.();
            } catch (e) {
              pluginErrorCounter.add(1, { plugin: name, event: 'destroy' });
              span.addEvent('destroy.error', { error: String(e) });
              console.error(`[PluginManager] Error during destroy() of plugin: ${name}`, e);
            }
            // Remove all event handlers registered by this plugin
            const subs = this.pluginSubscriptions.get(name) || [];
            for (const { type, handler } of subs) {
              const handlers = this.eventHandlers.get(type);
              if (handlers) {
                this.eventHandlers.set(type, handlers.filter(h => h !== handler));
              }
            }
            this.pluginSubscriptions.delete(name);
            this.plugins.splice(idx, 1);
            pluginUnloadCounter.add(1, { plugin: name });
            span.setStatus({ code: 1 });
            console.info(`[PluginManager] Unloaded plugin: ${name}`);
          } else {
            span.setStatus({ code: 2, message: `Tried to unload non-existent plugin: ${name}` });
            console.warn(`[PluginManager] Tried to unload non-existent plugin: ${name}`);
          }
        } else {
          span.setStatus({ code: 2, message: `Tried to unload non-existent plugin: ${name}` });
          console.warn(`[PluginManager] Tried to unload non-existent plugin: ${name}`);
        }
      } catch (e) {
        pluginErrorCounter.add(1, { plugin: name, event: 'unload' });
        span.setStatus({ code: 2, message: String(e) });
      } finally {
        span.end();
      }
    });
  }

  /**
   * Hot-reloads a plugin by name: unloads, re-imports, and re-registers it. Logs lifecycle events.
   */
  async reloadPlugin(name: string, entry: string, appContext: PluginAppContext = this.appContext) {
    return this.tracer.startActiveSpan('PluginManager.reloadPlugin', async span => {
      try {
        this.unloadPlugin(name);
        const plugin = await this.loadPluginFromDisk(entry);
        if (plugin) {
          this.register(plugin, appContext);
        }
        pluginReloadCounter.add(1, { plugin: name });
        span.setStatus({ code: 1 });
      } catch (e) {
        pluginErrorCounter.add(1, { plugin: name, event: 'reload' });
        span.setStatus({ code: 2, message: String(e) });
        this.appContext.publishEvent({
          type: 'Log',
          agentId: 'PluginManager',
          timestamp: new Date().toISOString(),
          payload: {
            level: 'error',
            message: `Failed to reload plugin: ${name}`,
            error: {
              type: e instanceof Error ? e.name : typeof e,
              message: e instanceof Error ? e.message : String(e),
              stack: e instanceof Error ? e.stack : undefined,
              context: { event: 'reload' }
            }
          }
        });
      } finally {
        span.end();
      }
    });
  }

  /**
   * Aggregates health/status for all registered plugins. Emits OTel spans/metrics for health checks.
   */
  async aggregateHealth(): Promise<Record<string, unknown>> {
    const health: Record<string, unknown> = {};
    for (const plugin of this.plugins) {
      const pluginName = typeof (plugin as any).name === 'string' ? (plugin as any).name : 'unknown';
      if (typeof (plugin as any).health === 'function') {
        try {
          const status = await (plugin as any).health();
          health[pluginName] = status;
          // OTel: 1=ok, 0=degraded, -1=error, -2=unknown
          let statusNum = -2;
          if (status && typeof status === 'object' && 'status' in status) {
            if (status.status === 'ok') statusNum = 1;
            else if (status.status === 'degraded') statusNum = 0;
            else if (status.status === 'error') statusNum = -1;
          }
          latestHealth[pluginName] = statusNum;
        } catch (e) {
          health[pluginName] = { status: 'error', error: String(e), timestamp: new Date().toISOString() };
          pluginHealthErrorCounter.add(1, { plugin: pluginName });
          latestHealth[pluginName] = -1;
        }
      } else {
        health[pluginName] = { status: 'unknown', error: 'No health() method', timestamp: new Date().toISOString() };
        latestHealth[pluginName] = -2;
      }
    }
    return health;
  }
}

