override async runTask(task: unknown): Promise<AgentResult> {
    // Integrate ReasoningLoopUtility for iterative reasoning
    const reasoning = new ReasoningLoopUtility();
    const events: AgentEvent[] = [];
    const emitEvent = async (event: { type: string; payload?: Record<string, unknown> }) => {
      const agentEvent: AgentEvent = {
        type: event.type,
        agentId: this.name,
        timestamp: new Date().toISOString(),
        ...(event.payload !== undefined ? { payload: event.payload } : {})
      };
      events.push(agentEvent);
      await publishEvent(agentEvent);
    };
    // Generate candidates (simulate multi-LLM for now)
    const candidates = [
      await reasoning.runLoop(typeof task === 'string' ? task : JSON.stringify(task), { maxSteps: 1, emitEvent }),
      await reasoning.runLoop(typeof task === 'string' ? task : JSON.stringify(task), { maxSteps: 1, emitEvent }),
      await reasoning.runLoop(typeof task === 'string' ? task : JSON.stringify(task), { maxSteps: 1, emitEvent })
    ].map(r => r.result);
    // Voting/selection
    const { winner, rationale, details } = await this.votingStrategy.vote(candidates, { task });
    await publishEvent({
      type: 'votingRationale',
      agentId: this.name,
      timestamp: new Date().toISOString(),
      payload: { rationale, details, candidates, winner }
    });
    return {
      output: { result: winner },
      success: true,
      logs: [
        'EnsembleAgent ran task (integrated ReasoningLoopUtility, modular voting)',
        ...candidates.map((c, i) => `[candidate ${i + 1}] ${c}`),
        rationale,
        ...events.map(e => `[event] ${e.type}: ${'payload' in e && e.payload ? JSON.stringify(e.payload) : ''}`)
      ]
    };
  }

