examplePlugin: Capability = {
  name: 'examplePlugin',
  /**
   * Called when the plugin is registered. Sets up event subscriptions.
   */
  async init(appContext: PluginAppContext) {
    return tracer.startActiveSpan('examplePlugin.init', async span => {
      try {
        let unsubscribe: (() => void) | undefined;
        const handler = (event: AgentEvent) => {
          if (event.type === 'Log') {
            appContext.publishEvent({
              type: 'Log',
              agentId: 'examplePlugin',
              timestamp: new Date().toISOString(),
              payload: { level: 'info', message: 'examplePlugin handled a Log event', details: event.payload }
            });
          }
        };
        if (typeof (appContext as any).pluginManager?.subscribe === 'function') {
          (appContext as any).pluginManager.subscribe('Log', handler, 'examplePlugin');
        } else {
          appContext.subscribeToEvent('Log', handler);
        }
        unsubscribe = () => {};
        (appContext as any)._examplePluginUnsub = unsubscribe;
        pluginInitCounter.add(1);
        span.setStatus({ code: 1 });
      } catch (e) {
        pluginErrorCounter.add(1, { event: 'init' });
        span.setStatus({ code: 2, message: String(e) });
        appContext.publishEvent({
          type: 'Log',
          agentId: 'examplePlugin',
          timestamp: new Date().toISOString(),
          payload: {
            level: 'error',
            message: 'Error in examplePlugin.init',
            error: {
              type: e instanceof Error ? e.name : typeof e,
              message: e instanceof Error ? e.message : String(e),
              stack: e instanceof Error ? e.stack : undefined,
              context: { event: 'init' }
            }
          }
        });
        throw e;
      } finally {
        span.end();
      }
    });
  },
  /**
   * Cleanup logic: ensure all event subscriptions are removed.
   */
  async shutdown() {
    return tracer.startActiveSpan('examplePlugin.shutdown', async span => {
      try {
        pluginShutdownCounter.add(1);
        span.setStatus({ code: 1 });
      } catch (e) {
        pluginErrorCounter.add(1, { event: 'shutdown' });
        span.setStatus({ code: 2, message: String(e) });
        throw e;
      } finally {
        span.end();
      }
    });
  },
  /**
   * Reload logic for hot-reload scenarios.
   */
  async reload() {
    return tracer.startActiveSpan('examplePlugin.reload', async span => {
      try {
        pluginReloadCounter.add(1);
        span.setStatus({ code: 1 });
      } catch (e) {
        pluginErrorCounter.add(1, { event: 'reload' });
        span.setStatus({ code: 2, message: String(e) });
        throw e;
      } finally {
        span.end();
      }
    });
  },
  /**
   * Health check for plugin status.
   */
  async health(): Promise<HealthStatus> {
    return tracer.startActiveSpan('examplePlugin.health', span => {
      pluginHealthCounter.add(1);
      const status: HealthStatus = { status: 'ok', timestamp: new Date().toISOString() };
      span.setStatus({ code: 1 });
      span.end();
      return status;
    });
  },
  /**
   * Optional: handle all events (wildcard).
   */
  async onEvent(event: AgentEvent) {
    return tracer.startActiveSpan('examplePlugin.onEvent', async span => {
      try {
        pluginOnEventCounter.add(1);
        if (event.type === 'TaskAssigned') {
          // ... handle TaskAssigned event
        }
        span.setStatus({ code: 1 });
      } catch (e) {
        pluginErrorCounter.add(1, { event: 'onEvent' });
        span.setStatus({ code: 2, message: String(e) });
        throw e;
      } finally {
        span.end();
      }
    });
  },
  /**
   * Returns a machine-usable, LLM-friendly description of the plugin.
   * NOTE: Keep this in sync with the Capability interface in capabilities/Capability.ts.
   */
  describe() {
    return {
      name: 'examplePlugin',
      description: 'A sample plugin for nootropic. Demonstrates plugin lifecycle, dynamic event subscription, and hot-reload safety.',
      license: 'MIT',
      isOpenSource: true,
      provenance: 'https://github.com/nootropic/nootropic',
      docsFirst: true,
