getSemgrepFindings.text:
export async function getSemgrepFindings(): Promise<Array<{
  id: string;
  file: string;
  startLine: number;
  endLine: number;
  ruleId: string;
  message: string;
  severity?: string;
  cwe?: string;
  owasp?: string;
  raw?: any;
}>> {
  // Run Semgrep scan and parse output (reuse plugin logic)
  return new Promise((resolve, reject) => {
    const proc = spawn('semgrep', ['scan', '--json', '.'], { shell: true });
    let output = '';
    proc.stdout?.on('data', (data) => { output += data.toString(); });
    proc.stderr?.on('data', (data) => { process.stderr.write(data); });
    proc.on('close', (code) => {
      if (code === 0) {
        try {
          const result = JSON.parse(output);
          const findings = (result.results || []).map((f: any) => ({
            id: `${f.check_id}:${f.path}:${f.start.line}`,
            file: f.path,
            startLine: f.start.line,
            endLine: f.end.line,
            ruleId: f.check_id,
            message: f.extra?.message || '',
            severity: f.extra?.severity,
            cwe: f.extra?.metadata?.cwe,
            owasp: f.extra?.metadata?.owasp,
            raw: f
          }));
          resolve(findings);
        } catch (e) {
          reject(e);
        }
      } else {
        reject(new Error('Semgrep scan failed'));
      }
    });
    proc.on('error', (err) => reject(err));
  });
}

