async function main() {
  const backlogRaw = await fs.promises.readFile(BACKLOG_PATH, 'utf-8');
  const backlogJson = JSON.parse(backlogRaw);
  const todos = backlogJson.backlog.filter((item: any) => item.id && item.id.startsWith('todo:'));
  const fileCounts: Record<string, number> = {};
  const staleness: { todo: any; days: number }[] = [];
  for (const todo of todos) {
    const file = (todo.id.split(':')[1] || '').split(':')[0];
    fileCounts[file] = (fileCounts[file] || 0) + 1;
    // Use note.timestamp, or fallback to none
    const days = getDaysSince(todo.note?.timestamp || todo.timestamp);
    staleness.push({ todo, days });
  }
  // Top 5 files by TODO count
  const topFiles = Object.entries(fileCounts).sort((a, b) => b[1] - a[1]).slice(0, 5).map(([file, count]) => ({ file, count }));
  // Top 5 oldest TODOs
  const oldestTodos = staleness.sort((a, b) => b.days - a.days).slice(0, 5).map(({ todo, days }) => ({ id: todo.id, description: todo.description, days }));
  // Prioritized list for next sprint: top priority, not ignored, not resolved, not stale
  const nextSprint = todos.filter((t: any) => (t.aiSuggestedPriority === 'top' || t.priority === 'top') && t.triage !== 'ignored' && t.triage !== 'resolved').slice(0, 10);
  const summary = { topFiles, oldestTodos, nextSprint };
  await fs.promises.writeFile(INSIGHTS_PATH, JSON.stringify(summary, null, 2));
  console.log('Backlog insights written to', INSIGHTS_PATH);
}

async function main() {
  const args = process.argv.slice(2);
  const dryRun = args.includes('--dry-run');
  const token = process.env['GITHUB_TOKEN'];
  const owner = process.env['GITHUB_OWNER'];
  const repo = process.env['GITHUB_REPO'];
  if (!token || !owner || !repo) {
    console.error('Missing required env vars: GITHUB_TOKEN, GITHUB_OWNER, GITHUB_REPO');
    process.exit(1);
  }
  const { Octokit } = await import('@octokit/rest');
  const octokit = new Octokit({ auth: token });
  const backlogPath = path.resolve('agentBacklog.json');
  const backlog = JSON.parse(fs.readFileSync(backlogPath, 'utf-8'));
  const actionable = [
    ...(Array.isArray(backlog.inProgress) ? backlog.inProgress : []),
    ...(Array.isArray(backlog.planned) ? backlog.planned : [])
  ];
  // Map: feature name -> { status, ... }
  const featureMap = new Map();
  for (const item of actionable) {
    if (item && item.feature) featureMap.set(item.feature, item);
  }
  // Fetch all open issues with a special label
  const label = 'nootropic-backlog';
  const issues = await octokit.paginate(octokit.issues.listForRepo, {
    owner, repo, state: 'open', labels: label, per_page: 100
  });
  const issueMap = new Map();
  for (const issue of issues) {
    if (issue.title) issueMap.set(issue.title, issue);
  }
  // Sync: create/update/close as needed
  const actions = [];
  // --- 2025 IssueOps best practices: sync status as labels for richer filtering ---
  const statusLabels = ['planned', 'in progress', 'complete'];
  // 1. Create or update issues for all actionable features
  for (const [feature, item] of featureMap.entries()) {
    const title = feature;
    const body = `**Feature:** ${feature}\n\n${item.rationale || item.description || ''}\n\nStatus: ${item.status || 'planned'}\n\n(Managed by nootropic IssueOps automation)`;
    const labels = [label, item.status && statusLabels.includes(item.status) ? item.status : 'planned'];
    if (issueMap.has(title)) {
      // Update if body/status/labels changed
      const issue = issueMap.get(title);
      const currentLabels = (issue.labels || []).map((l: any) => typeof l === 'string' ? l : l.name).filter(Boolean);
      const missingLabels = labels.filter(l => !currentLabels.includes(l));
      const extraLabels = currentLabels.filter((l: string) => statusLabels.includes(l) && !labels.includes(l));
      if (issue.body !== body) {
        actions.push({ type: 'update', number: issue.number, title, body });
        if (!dryRun) await octokit.issues.update({ owner, repo, issue_number: issue.number, body });
      }
      if (missingLabels.length > 0) {
        actions.push({ type: 'addLabels', number: issue.number, labels: missingLabels });
        if (!dryRun) await octokit.issues.addLabels({ owner, repo, issue_number: issue.number, labels: missingLabels });
      }
      for (const l of extraLabels) {
        actions.push({ type: 'removeLabel', number: issue.number, label: l });
        if (!dryRun) await octokit.issues.removeLabel({ owner, repo, issue_number: issue.number, name: l });
      }
      issueMap.delete(title);
    } else {
      // Create new issue
      actions.push({ type: 'create', title, body, labels });
      if (!dryRun) await octokit.issues.create({ owner, repo, title, body, labels });
    }
  }
  // 2. Close issues for features no longer in actionable backlog
  for (const [title, issue] of issueMap.entries()) {
    actions.push({ type: 'close', number: issue.number, title });
    if (!dryRun) await octokit.issues.update({ owner, repo, issue_number: issue.number, state: 'closed' });
  }
  // Summary
  if (actions.length === 0) {
    console.log('Backlog sync: No changes needed.');
  } else {
    for (const action of actions) {
      if (action.type === 'create') console.log(`Would create: ${action.title}`);
      if (action.type === 'update') console.log(`Would update: ${action.title}`);
      if (action.type === 'close') console.log(`Would close: ${action.title}`);
    }
    if (!dryRun) console.log('Backlog sync: Actions completed.');
  }
}

async function main() {
  const argv = yargs(helpers.hideBin(process.argv))
    .option('brokers', { type: 'string', demandOption: true, desc: 'Comma-separated list of Kafka brokers' })
    .option('dlq-topic', { type: 'string', demandOption: true, desc: 'DLQ topic to consume from' })
    .option('main-topic', { type: 'string', demandOption: true, desc: 'Main topic to replay to' })
    .option('from-beginning', { type: 'boolean', default: true, desc: 'Consume from beginning of DLQ topic' })
    .option('limit', { type: 'number', desc: 'Max number of DLQ events to replay' })
    .option('dry-run', { type: 'boolean', default: false, desc: 'Log what would be replayed, do not produce' })
    .option('help', { type: 'boolean', desc: 'Show help' })
    .argv as any;

  const brokers: string[] = argv.brokers?.split(',');
  const dlqTopic: string = argv['dlq-topic'];
  const mainTopic: string = argv['main-topic'];
  const fromBeginning: boolean = argv['from-beginning'];
  const limit: number | undefined = argv.limit;
  const dryRun: boolean = argv['dry-run'];

  if (!brokers || !dlqTopic || !mainTopic) {
    console.error('[dlqReplay] Missing required arguments. Use --help for usage.');
    process.exit(1);
  }

  const kafka = new Kafka({ brokers, logLevel: logLevel.WARN });
  const consumer = kafka.consumer({ groupId: `dlq-replay-${Math.random().toString(36).substring(2, 10)}` });
  const producer = kafka.producer();

  let replayed = 0;
  let errors = 0;
  let processed = 0;
  let shuttingDown = false;

  async function shutdown() {
    if (shuttingDown) return;
    shuttingDown = true;
    console.log('\n[dlqReplay] Shutting down...');
    try {
      await consumer.disconnect();
      await producer.disconnect();
    } catch (err) {
      console.error('[dlqReplay] Error during shutdown:', err);
    }
    printSummary();
    process.exit(0);
  }

  function printSummary() {
    console.log('\n[dlqReplay] Replay Summary:');
    console.log(`  Total processed: ${processed}`);
    console.log(`  Replayed:        ${replayed}`);
    console.log(`  Errors:          ${errors}`);
    console.log(`  Dry-run:         ${dryRun}`);
  }

  process.on('SIGINT', shutdown);
  process.on('SIGTERM', shutdown);

  await consumer.connect();
  await producer.connect();
  await consumer.subscribe({ topic: dlqTopic, fromBeginning });

  console.log(`[dlqReplay] Starting DLQ replay from ${dlqTopic} to ${mainTopic} (dryRun=${dryRun})...`);

  await consumer.run({
    eachMessage: async ({ topic: _topic, partition: _partition, message }: { topic: string; partition: number; message: Message }) => {
      // Suppress unused variable linter warnings for _topic and _partition
      void _topic;
      void _partition;
      if (shuttingDown) return;
      processed++;
      await tracer.startActiveSpan('dlqReplay.consumeDLQ', async (span: any) => {
        try {
          const dlqEvent = JSON.parse(message.value!.toString());
          const parsed = DLQEventSchema.safeParse(dlqEvent);
          if (!parsed.success) {
            const offsetStr = (message as any).offset ? String((message as any).offset) : 'unknown';
            console.error(`[dlqReplay] Invalid DLQ event at offset ${offsetStr}:`, parsed.error.issues);
            errors++;
            span.setStatus({ code: SpanStatusCode.ERROR, message: 'Invalid DLQ event' });
            return;
          }
          const originalEvent = dlqEvent.originalEvent;
          if (dryRun) {
            console.log(`[dry-run] Would replay event to ${mainTopic}:`, originalEvent);
            replayed++;
          } else {
            await tracer.startActiveSpan('dlqReplay.produceReplay', async (produceSpan: any) => {
              try {
                await producer.send({
                  topic: mainTopic,
                  messages: [{ value: JSON.stringify(originalEvent) }],
                });
                produceSpan.setStatus({ code: SpanStatusCode.OK });
                replayed++;
              } catch (produceErr) {
                console.error(`[dlqReplay] Error producing to ${mainTopic}:`, produceErr);
                produceSpan.setStatus({ code: SpanStatusCode.ERROR, message: String(produceErr) });
                errors++;
              } finally {
                produceSpan.end();
              }
            });
          }
          span.setStatus({ code: SpanStatusCode.OK });
        } catch (err) {
          console.error(`[dlqReplay] Error processing DLQ event:`, err);
          span.setStatus({ code: SpanStatusCode.ERROR, message: String(err) });
          errors++;
        } finally {
          span.end();
        }
      });
      if (limit && replayed >= limit) {
        console.log(`[dlqReplay] Replay limit reached (${limit}). Exiting...`);
        await shutdown();
      }
    },
  });
}

