async function main() {
  let depGraph = {};
  try { depGraph = JSON.parse(await fs.promises.readFile(DEP_GRAPH_PATH, 'utf-8')); } catch {}

  // --- ts-morph static analysis ---
  const project = new Project({ tsConfigFilePath: path.join(ROOT, 'tsconfig.json') });
  const files = project.getSourceFiles(['**/*.ts', '!**/node_modules/**', '!**/dist/**', '!**/.nootropic-cache/**', '!**/testdata/**', '!**/__tests__/**', '!**/copy/**', '!**/vendor/**', '!**/Flight Control/**', '!**/Rocketship copy/**']);

  const callGraph: Record<string, string[]> = {};
  const symbolTable: Record<string, string[]> = {};

  for (const file of files) {
    const filePath = file.getFilePath();
    callGraph[filePath] = [];
    symbolTable[filePath] = [];
    // Functions
    for (const fn of file.getFunctions()) {
      const fnName = fn.getName();
      if (!symbolTable[filePath]) symbolTable[filePath] = [];
      symbolTable[filePath].push(fnName ? fnName : '<anonymous function>');
      fn.forEachDescendant((node) => {
        if (Node.isCallExpression(node)) {
          const expr = node.getExpression();
          if (expr && callGraph[filePath]) {
            callGraph[filePath].push(expr.getText());
          }
        }
      });
    }
    // Classes
    for (const cls of file.getClasses()) {
      const clsName = cls.getName();
      if (!symbolTable[filePath]) symbolTable[filePath] = [];
      symbolTable[filePath].push(clsName ? clsName : '<anonymous class>');
      for (const method of cls.getMethods()) {
        const methodName = method.getName();
        if (!symbolTable[filePath]) symbolTable[filePath] = [];
        symbolTable[filePath].push(methodName ? methodName : '<anonymous method>');
        method.forEachDescendant((node) => {
          if (Node.isCallExpression(node)) {
            const expr = node.getExpression();
            if (expr && callGraph[filePath]) {
              callGraph[filePath].push(expr.getText());
            }
          }
        });
      }
    }
    // Variables
    for (const v of file.getVariableDeclarations()) {
      symbolTable[filePath].push(v.getName());
    }
  }

  // (Stub) Data flow graph
  const dataFlow: Record<string, unknown> = {};

  const contextGraph = { dependency: depGraph, callGraph, symbolTable, dataFlow };
  await fs.promises.writeFile(CONTEXT_GRAPH_PATH, JSON.stringify(contextGraph, null, 2));
  console.log('Context graph written to', CONTEXT_GRAPH_PATH);
}

renderCapabilityMd.text:
function renderCapabilityMd(cap: any): string {
  let md = `# ${cap.name}\n\n`;
  if (cap.description) md += `${cap.description}\n\n`;
  if (cap.usage) md += `**Usage:**\n\n\`${cap.usage}\`\n\n`;
  if (cap.methods || cap.functions) {
    md += '## Methods/Functions\n\n';
    const items = cap.methods || cap.functions;
    for (const m of items) {
      md += `- **${m.name}**: ${m.signature || ''} - ${m.description || ''}\n`;
    }
    md += '\n';
  }
  if (cap.schema) {
    md += '## Schema\n\n';
    md += '```json\n' + JSON.stringify(cap.schema, null, 2) + '\n```\n';
  }
  if (cap.bestPractices) {
    md += '## Best Practices\n\n';
    for (const bp of cap.bestPractices) {
      md += `- ${bp}\n`;
    }
    md += '\n';
  }
  if (cap.references) {
    md += '## References\n\n';
    for (const ref of cap.references) {
      md += `- ${ref}\n`;
    }
    md += '\n';
  }
  return md;
}

