  md += '_This file is auto-generated from agentBacklog.json. Do not edit manually._\n\n';
  if (Array.isArray(backlog.inProgress) && backlog.inProgress.length) {
    md += '## 🚧 In Progress\n\n';
    for (const item of backlog.inProgress) md += renderFeature(item) + '\n';
  }
  if (Array.isArray(backlog.planned) && backlog.planned.length) {
    md += '## 📝 Planned\n\n';
    for (const item of backlog.planned) md += renderFeature(item) + '\n';
  }
  if (Array.isArray(backlog.completed) && backlog.completed.length) {
    md += '## ✅ Completed\n\n';
    for (const item of backlog.completed) md += renderFeature(item) + '\n';
  }
  fs.mkdirSync(path.dirname(outPath), { recursive: true });
  fs.writeFileSync(outPath, md);
  console.log(`Roadmap generated: ${outPath}`);
}

async function main() {
  const project = new Project({ tsConfigFilePath: path.join(ROOT, 'tsconfig.json') });
  const files = project.getSourceFiles(['**/*.ts', '!**/node_modules/**', '!**/dist/**', '!**/.nootropic-cache/**', '!**/testdata/**', '!**/__tests__/**', '!**/copy/**', '!**/vendor/**', '!**/Flight Control/**', '!**/Rocketship copy/**']);
  const embeddings: Record<string, Record<string, { text: string }>> = {};
  for (const file of files) {
    const filePath = file.getFilePath();
    embeddings[filePath] = {};
    // Functions
    for (const fn of file.getFunctions()) {
      const fnName = fn.getName() || '<anonymous function>';
      embeddings[filePath][fnName] = { text: fn.getText() };
    }
    // Classes
    for (const cls of file.getClasses()) {
      const clsName = cls.getName() || '<anonymous class>';
      embeddings[filePath][clsName] = { text: cls.getText() };
      for (const method of cls.getMethods()) {
        const methodName = method.getName() || '<anonymous method>';
        embeddings[filePath][`${clsName}.${methodName}`] = { text: method.getText() };
      }
    }
    // Variables
    for (const v of file.getVariableDeclarations()) {
      const varName = v.getName();
      embeddings[filePath][varName] = { text: v.getText() };
    }
  }
  await fs.promises.writeFile(EMBEDDINGS_PATH, JSON.stringify(embeddings, null, 2));
  console.log('Semantic embeddings (text only) written to', EMBEDDINGS_PATH);
}

async function main() {
  const token = process.env['GITHUB_TOKEN'] || '';
  const owner = process.env['GITHUB_OWNER'] || '';
  const repo = process.env['GITHUB_REPO'] || '';
  const eventPath = process.env['GITHUB_EVENT_PATH'] || '';
  if (!token || !owner || !repo || !eventPath) {
    console.error('Missing required env vars: GITHUB_TOKEN, GITHUB_OWNER, GITHUB_REPO, GITHUB_EVENT_PATH');
    process.exit(1);
  }
  const { Octokit } = await import('@octokit/rest');
  const octokit = new Octokit({ auth: token });
  const event = JSON.parse(fs.readFileSync(eventPath, 'utf-8'));

  // Helper: post a comment
  async function postComment(issue_number: number, body: string) {
    await octokit.issues.createComment({ owner: owner as string, repo: repo as string, issue_number, body });
    console.log(`[comment] #${issue_number}: ${body}`);
  }
  // Helper: add label(s)
  async function addLabels(issue_number: number, labels: string[]) {
    await octokit.issues.addLabels({ owner: owner as string, repo: repo as string, issue_number, labels });
    console.log(`[label:add] #${issue_number}: ${labels.join(', ')}`);
  }
  // Helper: remove label(s)
  async function removeLabel(issue_number: number, label: string) {
    try {
      await octokit.issues.removeLabel({ owner: owner as string, repo: repo as string, issue_number, name: label });
      console.log(`[label:remove] #${issue_number}: ${label}`);
    } catch {
      // Ignore if label not present
    }
  }

  // Main event handling
  if (event.issue && event.action === 'opened') {
    // Issue opened: add 'triage' label and onboarding comment
    const issue_number = event.issue.number;
    await addLabels(issue_number, ['triage']);
    await postComment(issue_number, `👋 Welcome! This issue is now in triage. A maintainer will review it soon.\n\n_This is an automated onboarding message. See CONTRIBUTING.md for next steps._`);
  } else if (event.issue && event.action === 'labeled') {
    // Label added: post status update comment
    const issue_number = event.issue.number;
    const label = event.label?.name;
    if (label) {
      await postComment(issue_number, `🔖 Status update: \`${label}\` label added.`);
    }
  } else if (event.issue && event.action === 'unlabeled') {
    // Label removed: post status update comment
    const issue_number = event.issue.number;
    const label = event.label?.name;
    if (label) {
      await postComment(issue_number, `❌ Status update: \`${label}\` label removed.`);
    }
  } else if (event.comment && event.issue && event.action === 'created') {
    // New comment: check for .submit, .approve, .deny commands
    const issue_number = event.issue.number;
    const body = event.comment.body.trim();
    if (body.startsWith('.submit')) {
      await addLabels(issue_number, ['submitted']);
      await removeLabel(issue_number, 'triage');
      await postComment(issue_number, `✅ Issue submitted for review. Thank you!`);
    } else if (body.startsWith('.approve')) {
      await addLabels(issue_number, ['approved']);
      await removeLabel(issue_number, 'submitted');
      await postComment(issue_number, `🎉 Issue approved!`);
    } else if (body.startsWith('.deny')) {
      await addLabels(issue_number, ['denied']);
      await removeLabel(issue_number, 'submitted');
      await postComment(issue_number, `🚫 Issue denied. Please see feedback above.`);
    }
    // TODO: Add more commands as needed
  } else if (event.issue && event.action === 'closed') {
    // Issue closed: post closing comment
    const issue_number = event.issue.number;
    await postComment(issue_number, `🔒 Issue closed. Thank you for your contribution!`);
  } else if (event.issue && event.action === 'reopened') {
    // Issue reopened: post reopening comment
    const issue_number = event.issue.number;
    await postComment(issue_number, `♻️ Issue reopened. A maintainer will review it again.`);
  } else {
    console.log('No matching event/action for state-machine automation.');
  }

  // TODO: Add edge case handling (e.g., multiple labels, permission checks, onboarding checklist)
  // TODO: Add onboarding doc generation and link in onboarding comment
  // TODO: Add audit log output for all actions
}

