function isOssLicense(license: string) {
  // SPDX identifiers for common OSS licenses
  const oss = [
    'MIT', 'Apache-2.0', 'BSD-2-Clause', 'BSD-3-Clause', 'MPL-2.0', 'AGPL-3.0', 'GPL-3.0', 'LGPL-3.0', 'Unlicense', 'CC0-1.0'
  ];
  return oss.includes(license);
}

