function main() {
  if (!fs.existsSync(REGISTRY_PATH)) {
    console.error('Describe registry not found:', REGISTRY_PATH);
    process.exit(1);
  }
  const registry = JSON.parse(fs.readFileSync(REGISTRY_PATH, 'utf-8'));
  let hasError = false;
  const summary: string[] = [];
  summary.push('| Name | License | OSS | Provenance | CloudOnly | OptInRequired |');
  summary.push('|------|---------|-----|------------|-----------|---------------|');
  for (const cap of registry) {
    const { name, license, isOpenSource, provenance, cloudOnly, optInRequired } = cap;
    let row = `| ${name || ''} | ${license || ''} | ${isOpenSource ? '✅' : '❌'} | ${provenance || ''} | ${cloudOnly ? '✅' : ''} | ${optInRequired ? '✅' : ''} |`;
    summary.push(row);
    // Check required fields
    if (!name || !license || typeof isOpenSource !== 'boolean' || !provenance) {
      console.error(`❌ Capability '${name}' is missing required license, isOpenSource, or provenance fields.`);
      hasError = true;
    }
    // OSS enforcement
    if (!isOpenSource || !isOssLicense(license)) {
      if (!cloudOnly && !optInRequired) {
        console.error(`❌ Capability '${name}' is not open-source and not explicitly marked as cloudOnly/optInRequired.`);
        hasError = true;
      } else {
        console.warn(`⚠️  Capability '${name}' is non-OSS or paid/cloud. Explicit opt-in required.`);
      }
    }
  }
  console.log('\nLicense/OSS Compliance Table:');
  for (const line of summary) console.log(line);
  if (hasError) {
    console.error('\n❌ License/OSS compliance check failed. See errors above.');
    process.exit(1);
  } else {
    console.log('\n✅ License/OSS compliance check passed.');
    process.exit(0);
  }
}

