async function main(): Promise<void> {
  const args = process.argv.slice(2);
  if (args.includes('--refresh-manifest')) {
    const manifest = await scanCacheDir();
    await writeManifest(manifest);
    console.log('cache-manifest.json refreshed.');
    return;
  }
  if (args.includes('--validate-manifest')) {
    let manifest: CacheManifestEntry[];
    try {
      manifest = JSON.parse(await fs.readFile(MANIFEST_PATH, 'utf8'));
      manifest = manifest.filter((entry: any) => typeof entry.fileName === 'string');
    } catch {
      console.error('Manifest missing or unreadable. Run with --refresh-manifest.');
      process.exit(1);
    }
    const files = await scanCacheDir();
    const manifestFiles = new Set(manifest.map((f: CacheManifestEntry) => f.fileName));
    const actualFiles = new Set(files.map((f: CacheManifestEntry) => f.fileName));
    for (const f of manifestFiles) {
      if (!actualFiles.has(f)) {
        console.warn(`Stale manifest entry: ${f}`);
      }
    }
    for (const f of actualFiles) {
      if (!manifestFiles.has(f)) {
        console.warn(`Missing manifest entry: ${f}`);
      }
    }
    console.log('Manifest validation complete.');
    return;
  }
  // Default: just refresh manifest
  const manifest = await scanCacheDir();
  await writeManifest(manifest);
  console.log('cache-manifest.json refreshed.');
}

cliEntrypoint.text:
async function cliEntrypoint(): Promise<void> {
  const args = process.argv.slice(2);
  const sub = args[0];
  if (sub === 'list') {
    const manifest = await scanCacheDir();
    if (args.includes('--json')) {
      console.log(JSON.stringify(manifest, null, 2));
    } else {
      for (const entry of manifest) {
        console.log(`${entry.fileName} (${entry.type}) - ${entry.size} bytes - ${entry.lastModified}${entry.compressed ? ' [compressed]' : ''}${entry.archive ? ' [archive]' : ''}`);
      }
    }
    return;
  }
  if (sub === 'prune') {
    // Parse flags
    const dryRun = args.includes('--dry-run');
    const maxAgeIdx = args.indexOf('--max-age');
    const maxSizeIdx = args.indexOf('--max-size');
    const jsonOut = args.includes('--json');
    let maxAgeDays: number | undefined;
    let maxSizeMB: number | undefined;
    const maxAgeArg = args[maxAgeIdx + 1];
    const maxSizeArg = args[maxSizeIdx + 1];
    if (maxAgeIdx !== -1 && typeof maxAgeArg === 'string') {
      maxAgeDays = parseFloat(maxAgeArg);
    }
    if (maxSizeIdx !== -1 && typeof maxSizeArg === 'string') {
      maxSizeMB = parseFloat(maxSizeArg);
    }
    const manifest = await scanCacheDir();
    const now = Date.now();
    function isValidManifestEntry(entry: any): entry is CacheManifestEntry {
      return entry && typeof entry.fileName === 'string';
    }
    let toPrune = manifest.filter(entry => {
      const ageOk = maxAgeDays !== undefined ? (now - Date.parse(entry.lastModified)) > maxAgeDays * 86400000 : false;
      const sizeOk = maxSizeMB !== undefined ? entry.size > maxSizeMB * 1024 * 1024 : false;
      return ageOk || sizeOk;
    });
    toPrune = toPrune.filter(isValidManifestEntry);
    const results: any[] = [];
    for (const entry of toPrune) {
      const filePath = entry.archive ? path.join(ARCHIVE_DIR, String(entry.fileName)) : path.join(CACHE_DIR, String(entry.fileName));
      if (dryRun) {
        results.push({ file: entry.fileName, action: 'would-delete', path: filePath });
      } else {
        try {
          await fs.unlink(filePath);
          results.push({ file: entry.fileName, action: 'deleted', path: filePath });
        } catch (err) {
          results.push({ file: entry.fileName, action: 'error', error: String(err), path: filePath });
        }
      }
    }
    if (!dryRun) {
      // Refresh manifest after deletion
      const newManifest = await scanCacheDir();
      await writeManifest(newManifest);
    }
    if (jsonOut) {
      console.log(JSON.stringify({ pruned: results }, null, 2));
    } else {
      for (const r of results) {
        if (r.action === 'deleted') {
          console.log(`Deleted: ${r.file}`);
        } else if (r.action === 'would-delete') {
          console.log(`Would delete: ${r.file}`);
        } else {
          console.warn(`Error deleting ${r.file}: ${r.error}`);
        }
      }
    }
    return;
  }
  if (sub === 'compress') {
    // Compress eligible files (not already compressed, not in archive)
    const dryRun = args.includes('--dry-run');
    const manifest = await scanCacheDir();
    const toCompress = manifest.filter(entry => !entry.compressed && !entry.archive && entry.type !== 'other');
    const results: any[] = [];
    const zlib = await import('zlib');
    const fsSync = await import('fs');
    for (const entry of toCompress) {
      const srcPath = path.join(CACHE_DIR, entry.fileName);
      const destPath = path.join(ARCHIVE_DIR, entry.fileName + '.gz');
      if (dryRun) {
        results.push({ file: entry.fileName, action: 'would-compress', src: srcPath, dest: destPath });
        continue;
      }
      try {
        await new Promise<void>((resolve, reject) => {
          const input = fsSync.createReadStream(srcPath);
          const output = fsSync.createWriteStream(destPath);
          const gzip = zlib.createGzip();
          input.pipe(gzip).pipe(output);
          output.on('finish', () => resolve());
          output.on('error', reject);
          input.on('error', reject);
        });
        results.push({ file: entry.fileName, action: 'compressed', src: srcPath, dest: destPath });
        // Optionally delete original after compress
        await fs.unlink(srcPath);
      } catch (err) {
        results.push({ file: entry.fileName, action: 'error', error: String(err), src: srcPath });
      }
    }
    // Refresh manifest after compression
    if (!dryRun) {
      const newManifest = await scanCacheDir();
      await writeManifest(newManifest);
    }
    if (args.includes('--json')) {
      console.log(JSON.stringify({ compressed: results }, null, 2));
    } else {
      for (const r of results) {
        if (r.action === 'compressed') {
          console.log(`Compressed: ${r.file}`);
        } else if (r.action === 'would-compress') {
          console.log(`Would compress: ${r.file}`);
        } else {
          console.warn(`Error compressing ${r.file}: ${r.error}`);
        }
      }
    }
    return;
  }
  if (sub === 'restore') {
    // Restore a file from archive (decompress .gz)
    const file = args[1];
    const dryRun = args.includes('--dry-run');
    if (!file) {
      console.error('Usage: restore <file> [--dry-run]');
      process.exit(1);
    }
    // Only allow restoring files that exist in archive and are .gz
    const archivePath = path.join(ARCHIVE_DIR, file.endsWith('.gz') ? file : file + '.gz');
    const destFile = file.replace(/\.gz$/, '');
    const destPath = path.join(CACHE_DIR, destFile);
    if (!await fs.stat(archivePath).then(() => true, () => false)) {
      console.error(`Archive file not found: ${archivePath}`);
      process.exit(1);
    }
    if (dryRun) {
      console.log(`Would restore: ${archivePath} -> ${destPath}`);
      return;
    }
    try {
      const zlib = await import('zlib');
      const fsSync = await import('fs');
      await new Promise<void>((resolve, reject) => {
        const input = fsSync.createReadStream(archivePath);
        const output = fsSync.createWriteStream(destPath);
        const gunzip = zlib.createGunzip();
        input.pipe(gunzip).pipe(output);
        output.on('finish', () => resolve());
        output.on('error', reject);
        input.on('error', reject);
      });
      console.log(`Restored: ${destFile}`);
      // Optionally, do not delete archive file after restore
      // await fs.unlink(archivePath);
      // Refresh manifest
      const newManifest = await scanCacheDir();
      await writeManifest(newManifest);
    } catch (err) {
      console.error(`Error restoring ${file}: ${err}`);
      process.exit(1);
    }
    return;
  }
  if (sub === 'report') {
    // Output cache health/summary
    const manifest = await scanCacheDir();
    let totalSize = 0;
    let fileCount = 0;
    let oldest: string | null = null;
    let newest: string | null = null;
    for (const entry of manifest) {
      totalSize += entry.size;
      fileCount++;
      if (!oldest || entry.lastModified < oldest) oldest = entry.lastModified;
      if (!newest || entry.lastModified > newest) newest = entry.lastModified;
    }
    // Check for anomalies
    const orphaned = [];
    for (const entry of manifest) {
      const filePath = entry.archive ? path.join(ARCHIVE_DIR, entry.fileName) : path.join(CACHE_DIR, entry.fileName);
      if (!await fs.stat(filePath).then(() => true, () => false)) {
        orphaned.push(entry.fileName);
      }
    }
    const health = {
      totalSizeBytes: totalSize,
      fileCount,
      oldestFile: oldest,
      newestFile: newest,
      orphanedFiles: orphaned,
      manifestStatus: 'ok',
    };
    if (args.includes('--json')) {
      console.log(JSON.stringify({ manifest, health }, null, 2));
    } else {
      console.log(`Cache health: ${fileCount} files, ${totalSize} bytes, oldest: ${oldest}, newest: ${newest}`);
      if (orphaned.length) {
        console.warn('Orphaned files:', orphaned.join(', '));
      }
    }
    return;
  }
  // Fallback to original main for legacy flags
  await main();
}

