    user,
    rating,
    timestamp: new Date().toISOString(),
    ...(review ? { review } : {})
  };
  try {
    await submitPluginFeedback(feedback);
    console.log('Feedback submitted successfully.');
  } catch (e) {
    console.error('Failed to submit feedback:', e);
    process.exit(1);
  }
}

