class DefaultShimiBackend implements ShimiSemanticBackend {
  constructor(private llmAdapter?: ShimiLLMAdapter) {}
  async similarity(a: string, b: string): Promise<number> {
    if (this.llmAdapter) {
      const [vecA, vecB] = await Promise.all([
        this.llmAdapter.embedText(a) ?? [],
        this.llmAdapter.embedText(b) ?? []
      ]);
      if (vecA.length === 0 || vecB.length === 0) return Math.random();
      return this.cosineSimilarity(vecA, vecB);
    }
    // TODO: Plug in real LLM/embedding backend
    return Math.random();
  }
  async mergeConcepts(a: string, b: string, parent?: string): Promise<string> {
    // TODO: Plug in real LLM/embedding backend for concept merging
    return `Abstract(${a},${b}${parent ? ',' + parent : ''})`;
  }
  private cosineSimilarity(a: number[], b: number[]): number {
    const dot = a.reduce((sum, ai, i) => sum + ai * b[i], 0);
    const normA = Math.sqrt(a.reduce((sum, ai) => sum + ai * ai, 0));
    const normB = Math.sqrt(b.reduce((sum, bi) => sum + bi * bi, 0));
    return dot / (normA * normB);
  }
}

