class NomicEmbedBackend implements ShimiSemanticBackend {
  private apiUrl: string;
  private apiKey?: string;
  constructor(options?: { apiUrl?: string; apiKey?: string }) {
    this.apiUrl = (options && typeof options.apiUrl === 'string' && options.apiUrl.length > 0)
      ? options.apiUrl
      : 'https://api-atlas.nomic.ai/v1/embedding/text';
    this.apiKey = options && typeof options.apiKey === 'string' && options.apiKey.length > 0 ? options.apiKey : undefined;
  }
  async similarity(a: string, b: string): Promise<number> {
    const [vecA, vecB] = await Promise.all([
      this.embed(a),
      this.embed(b)
    ]);
    if (!vecA || !vecB) throw new Error('Embedding failed');
    return this.cosineSimilarity(vecA, vecB);
  }
  async mergeConcepts(a: string, b: string, parent?: string): Promise<string> {
    // Use LLM to generate an abstracted summary (stub: concatenate)
    return `Abstracted(${a},${b}${parent ? ',' + parent : ''})`;
  }
  private async embed(text: string): Promise<number[]> {
    const body = JSON.stringify({ model: 'nomic-embed-text-v1', texts: [text] });
    const headers: Record<string, string> = { 'Content-Type': 'application/json' };
    if (this.apiKey) headers['Authorization'] = `Bearer ${this.apiKey}`;
    const res = await fetch(this.apiUrl, { method: 'POST', headers, body });
    const data: unknown = await res.json();
    if (
      typeof data !== 'object' || data === null ||
      !('embeddings' in data) ||
      !Array.isArray((data as any).embeddings) ||
      !Array.isArray((data as any).embeddings[0])
    ) {
      throw new Error('Nomic API error');
    }
    const embeddings = (data as { embeddings: number[][] }).embeddings;
    if (!embeddings || !embeddings[0]) throw new Error('Nomic API returned undefined embedding');
    return embeddings[0];
  }
  private cosineSimilarity(a: number[], b: number[]): number {
    if (!a || !b || a.length !== b.length) return 0;
    const dot = a.reduce((sum, ai, i) => sum + ai * (b[i] ?? 0), 0);
    const normA = Math.sqrt(a.reduce((sum, ai) => sum + ai * ai, 0));
    const normB = Math.sqrt(b.reduce((sum, bi) => sum + (bi ?? 0) * (bi ?? 0), 0));
    if (normA === 0 || normB === 0) return 0;
    return dot / (normA * normB);
  }
}

