export async function syncWithRemote(localMemories: SastFeedbackMemory[], remoteAdapter: any): Promise<SastFeedbackMemory[]> {
  const span = trace.getTracer('sastMemories').startSpan('syncWithRemote');
  const remoteMemories = await remoteAdapter.downloadMemories();
  const merged = await remoteAdapter.mergeMemories(localMemories, remoteMemories);
  await remoteAdapter.uploadMemories(merged);
  span.end();
  return merged;
}

mergeWithRemote.text:
export function mergeWithRemote(local: SastFeedbackMemory[], remote: SastFeedbackMemory[]): SastFeedbackMemory[] {
  const span = trace.getTracer('sastMemories').startSpan('mergeWithRemote');
  const seen = new Set<string>();
  const canonicalId = (m: SastFeedbackMemory) => `${m.tool}:${m.file}:${m.ruleId ?? ''}:${m.id}`;
  const merged = [...local, ...remote].filter(mem => {
    const id = canonicalId(mem);
    if (seen.has(id)) return false;
    seen.add(id);
    return true;
  });
  span.end();
  return merged;
}

